// 添加折线图
const chartData = {
    type: "line",
    options: {
        show_legend: false
    },
    series: [
        { values: "'Data'!B2:B5" }
    ],
    categories: [{ name: "'Data'!A2:A5" }]
}

const chartWS = XLSX.utils.json_to_sheet([chartData], {skipHeader: true});
XLSX.utils.book_append_sheet(wb, chartWS, "Chart");

// 保存工作簿
XLSX.writeFile(wb, 'output.xlsx');
